import{c as t,Q as o,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Claude Code vs Codex vs Aider vs OpenCode vs Pi 2026","description":"","frontmatter":{"title":"Claude Code vs Codex vs Aider vs OpenCode vs Pi 2026","date":"2026-04-01T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-01-ai-coding-harness-agents-2026-jock.md","filePath":"research/ai-articles/scored/2026-04-01-ai-coding-harness-agents-2026-jock.md","lastUpdated":1779894392000}'),n={name:"research/ai-articles/scored/2026-04-01-ai-coding-harness-agents-2026-jock.md"};function s(i,e,d,l,h,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<blockquote><p>Source: <a href="https://thoughts.jock.pl/p/ai-coding-harness-agents-2026" target="_blank" rel="noreferrer">https://thoughts.jock.pl/p/ai-coding-harness-agents-2026</a> Fetched: 2026-05-08</p></blockquote><h1 id="claude-code-vs-codex-vs-aider-vs-opencode-vs-pi-2026" tabindex="-1">Claude Code vs Codex vs Aider vs OpenCode vs Pi 2026 <a class="header-anchor" href="#claude-code-vs-codex-vs-aider-vs-opencode-vs-pi-2026" aria-label="Permalink to &quot;Claude Code vs Codex vs Aider vs OpenCode vs Pi 2026&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This comprehensive comparison examines AI coding harnesses—tools that enable autonomous code execution without direct human supervision. The author, Pawel Jozefiak, distinguishes between pair programming tools (which assist supervised development) and agent orchestrators (which operate autonomously).</p><h2 id="key-distinction-categories" tabindex="-1">Key Distinction: Categories <a class="header-anchor" href="#key-distinction-categories" aria-label="Permalink to &quot;Key Distinction: Categories&quot;">​</a></h2><p>The article emphasizes that not all &quot;AI coding harnesses&quot; serve the same purpose:</p><p><strong>Coding Tools</strong> function as pair programmers requiring human direction at each step. Examples include Aider and Codex CLI, designed for incremental improvements rather than autonomous overnight execution.</p><p><strong>Agent Orchestrators</strong> tackle goals independently across multiple files and decision points. Claude Code exemplifies this category, maintaining coherence across lengthy task chains without human intervention.</p><h2 id="the-harness-effect" tabindex="-1">The Harness Effect <a class="header-anchor" href="#the-harness-effect" aria-label="Permalink to &quot;The Harness Effect&quot;">​</a></h2><p>A critical finding: harness quality matters as much as the underlying model. Research demonstrates identical models produce dramatically different results in different harnesses. One study showed &quot;the same model inside different harnesses achieved 77% versus 93% performance&quot; depending on implementation architecture rather than model capability.</p><h2 id="tool-evaluations" tabindex="-1">Tool Evaluations <a class="header-anchor" href="#tool-evaluations" aria-label="Permalink to &quot;Tool Evaluations&quot;">​</a></h2><h3 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h3><p><strong>Strengths:</strong> Excels at complex multi-file tasks and overnight autonomous runs. Includes CLAUDE.md for project context persistence, Agent Teams functionality, and computer use capabilities.</p><p><strong>Limitations:</strong> Context loss after 2-hour sessions; 3-4x higher token consumption than alternatives.</p><p><strong>Best for:</strong> Architecture-level changes requiring consistent context across numerous steps.</p><h3 id="codex-cli" tabindex="-1">Codex CLI <a class="header-anchor" href="#codex-cli" aria-label="Permalink to &quot;Codex CLI&quot;">​</a></h3><p><strong>Strengths:</strong> Exceptional at app development (iOS, macOS, web). Operates in cloud containers, enabling disconnected task execution.</p><p><strong>Limitations:</strong> Struggles maintaining coherence across multi-step chains with dependencies.</p><p><strong>Best for:</strong> Focused, contained coding tasks with clear specifications.</p><h3 id="aider" tabindex="-1">Aider <a class="header-anchor" href="#aider" aria-label="Permalink to &quot;Aider&quot;">​</a></h3><p><strong>Strengths:</strong> Open-source, 4.2x token efficiency advantage, git-first approach creating auditable commits, BYOM flexibility.</p><p><strong>Limitations:</strong> Doesn&#39;t orchestrate across extensive file bases or coordinate sub-agents.</p><p><strong>Best for:</strong> Budget-conscious setups and incremental refactoring with full audit trails.</p><h3 id="opencode" tabindex="-1">OpenCode <a class="header-anchor" href="#opencode" aria-label="Permalink to &quot;OpenCode&quot;">​</a></h3><p><strong>Strengths:</strong> Supports 75+ LLM providers with seamless switching, accommodating various backends from Anthropic to open-weight models.</p><p><strong>Limitations:</strong> Lacks persistent project context and deep autonomous capabilities.</p><p><strong>Best for:</strong> Model experimentation and teams with multiple provider subscriptions.</p><h3 id="pi" tabindex="-1">Pi <a class="header-anchor" href="#pi" aria-label="Permalink to &quot;Pi&quot;">​</a></h3><p><strong>Strengths:</strong> Primitives-first design offering full configuration control. RPC mode enables embedding within larger systems. Fast and flexible implementation.</p><p><strong>Limitations:</strong> Anthropic doesn&#39;t permit Max subscription credits on third-party harnesses, requiring separate API billing for Claude access.</p><p><strong>Best for:</strong> Custom harness architectures and systems where coding agents integrate as components (with GPT or open-weight models).</p><h3 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h3><p><strong>Strengths:</strong> Superior IDE experience with supervised agent mode. Design Mode for mockup-to-implementation workflows. Parallel agent tabs.</p><p><strong>Limitations:</strong> Not designed for autonomous overnight execution; requires human supervision.</p><p><strong>Best for:</strong> Developers present at the keyboard seeking integrated IDE-plus-agent functionality.</p><h2 id="benchmark-context" tabindex="-1">Benchmark Context <a class="header-anchor" href="#benchmark-context" aria-label="Permalink to &quot;Benchmark Context&quot;">​</a></h2><p><strong>SWE-bench Pro</strong> provides cleaner metrics than the contaminated original SWE-bench, with GPT-5.4-Codex leading at 56.8%.</p><p><strong>Terminal-Bench 2.0</strong> better reflects agentic autonomous work, showing &quot;Claude Code harness at 92.1% versus Codex CLI at 77.3%&quot;—a more relevant signal for overnight tasks than standard code-editing scores.</p><h2 id="decision-framework" tabindex="-1">Decision Framework <a class="header-anchor" href="#decision-framework" aria-label="Permalink to &quot;Decision Framework&quot;">​</a></h2><p>Selection depends on specific workflow requirements:</p><ul><li><strong>Autonomous overnight execution:</strong> Claude Code (infrastructure designed for this purpose)</li><li><strong>App development:</strong> Codex CLI with GPT-5.4</li><li><strong>Budget constraints:</strong> Aider with cheaper backends</li><li><strong>Model flexibility:</strong> OpenCode or Aider</li><li><strong>Custom systems:</strong> Pi (with GPT or open-weight models)</li><li><strong>Supervised development:</strong> Cursor</li></ul><h2 id="additional-tools-mentioned" tabindex="-1">Additional Tools Mentioned <a class="header-anchor" href="#additional-tools-mentioned" aria-label="Permalink to &quot;Additional Tools Mentioned&quot;">​</a></h2><ul><li><strong>Goose:</strong> Open-source, MCP-based, general-purpose automation</li><li><strong>Cline:</strong> Multi-IDE support across VS Code, JetBrains, Neovim</li><li><strong>Gemini CLI:</strong> Free tier with generous limits (Google)</li><li><strong>Devin:</strong> Full autonomy with cloud sandbox at $20/month plus compute costs</li></ul><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>The author recommends Claude Code for autonomous execution, emphasizing that &quot;harness tuning matters as much as model quality.&quot; The choice depends entirely on whether developers remain present, whether tasks require extensive chaining, budget constraints, and whether autonomy is essential.</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心發現-harness-品質與模型一樣重要" tabindex="-1">核心發現：Harness 品質與模型一樣重要 <a class="header-anchor" href="#核心發現-harness-品質與模型一樣重要" aria-label="Permalink to &quot;核心發現：Harness 品質與模型一樣重要&quot;">​</a></h3><p>研究顯示：<strong>相同模型在不同 harness 中達到 77% vs 93% 的效能</strong>，差異完全來自實作架構而非模型能力。</p><h3 id="兩大類工具的根本差異" tabindex="-1">兩大類工具的根本差異 <a class="header-anchor" href="#兩大類工具的根本差異" aria-label="Permalink to &quot;兩大類工具的根本差異&quot;">​</a></h3><table tabindex="0"><thead><tr><th>類別</th><th>特性</th><th>代表工具</th></tr></thead><tbody><tr><td><strong>Coding Tools（配對程式設計）</strong></td><td>每步需要人工指示，增量式改進</td><td>Aider、Codex CLI</td></tr><tr><td><strong>Agent Orchestrators（自主執行器）</strong></td><td>跨多檔案獨立處理目標，無需人工監督</td><td>Claude Code</td></tr></tbody></table><h3 id="各工具詳細比較" tabindex="-1">各工具詳細比較 <a class="header-anchor" href="#各工具詳細比較" aria-label="Permalink to &quot;各工具詳細比較&quot;">​</a></h3><p><strong>Claude Code</strong></p><ul><li>優勢：複雜多檔案任務、夜間自主執行、CLAUDE.md 專案 context 持久化、Agent Teams 功能</li><li>限制：2 小時 session 後 context 丟失、token 消耗為其他工具的 3-4 倍</li><li>最適合：需要跨多步驟保持一致 context 的架構層面變更</li></ul><p><strong>Codex CLI</strong></p><ul><li>優勢：app 開發（iOS/macOS/Web）、雲端容器隔離執行（可離線）</li><li>限制：難以維持有依賴關係的多步驟鏈一致性</li><li>最適合：規格清楚的聚焦式程式任務</li></ul><p><strong>Aider</strong></p><ul><li>優勢：開源、4.2x token 效率優勢、git-first 方式建立可審計的 commit、BYOM 彈性</li><li>限制：不跨大型檔案庫編排，不協調子代理</li><li>最適合：預算敏感設定和需要完整審計軌跡的漸進式重構</li></ul><p><strong>OpenCode</strong></p><ul><li>優勢：支援 75+ LLM 供應商無縫切換</li><li>限制：缺乏持久專案 context 和深度自主能力</li><li>最適合：需要試驗多個模型供應商的團隊</li></ul><p><strong>Pi</strong></p><ul><li>優勢：primitives-first 設計、完整配置控制、RPC 模式可嵌入大型系統</li><li>限制：Anthropic 不允許 Max 訂閱積分用於第三方 harness，需額外 API 計費</li><li>最適合：客製化 harness 架構（搭配 GPT 或開源模型）</li></ul><h3 id="benchmark-比較" tabindex="-1">Benchmark 比較 <a class="header-anchor" href="#benchmark-比較" aria-label="Permalink to &quot;Benchmark 比較&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>說明</th><th>結果</th></tr></thead><tbody><tr><td><strong>SWE-bench Pro</strong></td><td>比被污染的原版更乾淨的指標</td><td>GPT-5.4-Codex 領先 56.8%</td></tr><tr><td><strong>TerminalBench 2.0</strong></td><td>更能反映 Agent 自主工作</td><td>Claude Code 92.1% vs Codex CLI 77.3%</td></tr></tbody></table><p>TerminalBench 2.0 是夜間自主執行任務更相關的信號，比標準程式碼編輯分數更有意義。</p><h3 id="決策框架" tabindex="-1">決策框架 <a class="header-anchor" href="#決策框架" aria-label="Permalink to &quot;決策框架&quot;">​</a></h3><ul><li>夜間自主執行 → <strong>Claude Code</strong></li><li>App 開發 → <strong>Codex CLI + GPT-5.4</strong></li><li>預算限制 → <strong>Aider + 較便宜的後端</strong></li><li>模型彈性 → <strong>OpenCode 或 Aider</strong></li><li>自訂系統 → <strong>Pi（搭配 GPT 或開源模型）</strong></li><li>人工監督開發 → <strong>Cursor</strong></li></ul><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>決策框架可直接用於工具選型；TerminalBench 2.0 補充 benchmark 視角</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>同模型不同 harness 77%→93% 提升是重要發現；工具分類方式新穎</td></tr><tr><td>C. 證據品質</td><td>8/10</td><td>TerminalBench 2.0 數據、多工具 benchmark 比較有具體數字</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>每工具比較詳細但缺乏實作建議</td></tr><tr><td>E. 泛化性</td><td>6/10</td><td>聚焦 AI coding 工具，領域特化程度較高</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.05/10</strong></td><td>7×0.3+7×0.2+8×0.2+7×0.15+6×0.15 = 2.1+1.4+1.6+1.05+0.9</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（工具選型決策補充）<br><strong>整合狀態</strong>：待實作</p>',71)])])}const p=t(n,[["render",s]]);export{g as __pageData,p as default};
